import { useEffect, useRef, useState } from 'react';
import styles from './index.module.less';
import _ from 'lodash';
import { history } from 'react-alive-router';
import PageBg from '../components/page-bg/page-bg';
import BgRect from '../components/grid/bg-rect';
import icon02a from '../images/item02a.png';
import icon02b from '../images/item02b.png';
import icon03a from '../images/item03a.png';
import icon03b from '../images/item03b.png';
import icon03c from '../images/item03c.png';

function App(props) {
  const [type, setType] = useState('');
    useEffect(() => {
      setType(_.get(props, 'searchParams.type'));
    }, []);
  return (
    <PageBg filter={!!type} className={styles['page-race-mode-detail']}>
      <BgRect type="c" wrapClassName={styles['bg-rect-wrap']} className={`${styles['rect-desc']} ${type === 'high' ? styles['high'] : ''}`}>
        <div className={`flex-aic ${styles['desc-til']}`}>
          <img src={type === 'basic' ? icon02a : icon02b} className={styles['desc-icon']} />
          <div className={styles['desc-til-tx']}>{type === 'basic' ? '初赛' : '进阶赛'}规则说明</div>
        </div>
        {type === 'basic' ? (
          <div className={styles['desc-rows']}>
            <div className={styles['desc-row']}>选手需在300秒内完成随机生成的食安题目。</div>
            <div className={styles['desc-row']}>答对100%全部题目即可视为“通关”。</div>
            <div className={styles['desc-row']}>通关后可解锁“通关抽奖”入口，赢取红包。</div>
          </div>
        ) : (
          <div className={styles['desc-rows']}>
            <div className={styles['desc-row']}>选手需在300秒内完成5条题目的回答。</div>
            <div className={styles['desc-row']}>答对100%全部题目即可视为“通关”。</div>
          </div>
        )}
      </BgRect>
      {type === 'basic' ? (
        <BgRect type="b" wrapClassName={styles['bg-rect-wrap']} className={`flex-aic-jcsb ${styles['rect-pro']}`} onClick={() => history.push('#/race-mode-scene')}>
          <div className={styles['pro-left']}>
            <div className={styles['pro-til']}>开始初赛挑战</div>
            <div className={styles['pro-tip']}>随机抽取食安题库，限时冲关</div>
          </div>
          <img src={icon03a} className={styles['pro-icon3a']} />
        </BgRect>
      ) : (
        <BgRect wrapClassName={styles['bg-rect-wrap']} className={`flex-aic-jcsb ${styles['rect-pro']} ${styles['rect-pro-high']}`} onClick={() => history.push('#/race-mode-scene')}>
          <div className={styles['pro-left']}>
            <div className={styles['pro-til']}>开始进阶挑战</div>
            <div className={styles['pro-tip']}>随机抽取食安题库，限时冲关</div>
          </div>
          <img src={icon03b} className={styles['pro-icon3a']} />
        </BgRect>
      )}
      <BgRect wrapClassName={styles['bg-rect-wrap']} className={`flex-aic-jcsb ${styles['rect-pro']}`}>
        <div className={styles['pro-left']}>
          <div className={`flex-aic ${styles['pro-til']}`}>
            <div>通关抽奖</div>
            <div className={`${styles['pro-tag']} ${styles['ash']}`}>未获资格</div>
            <div className={`${styles['pro-tag']} ${styles['purple']}`}>未获奖</div>
            <div className={`${styles['pro-tag']} ${styles['green']}`}>已获奖</div>
          </div>
          <div className={styles['pro-tip']}>通过“300秒挑战”后自动开启</div>
        </div>
        <img src={icon03c} className={styles['pro-icon3c']} />
      </BgRect>
    </PageBg>
  );
}

export default App;
